import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export const ADD_DISH_TO_ORDER = 'ADD_DISH_TO_ORDER'
export const REMOVE_DISH_FROM_ORDER = 'REMOVE_DISH_FROM_ORDER'
export const DECREMENT_DISH_QUANTITY_FROM_ORDER = 'DECREMENT_DISH_QUANTITY_FROM_ORDER'

export default new Vuex.Store({
  state: {
    order: {}
  },
  getters: {
    dishes: state => Object.values(state.order),
    dishCount: state => Object.values(state.order).reduce(
      (total, dish) => total + (dish.quantity || 0), 0
    )
  },
  mutations: {
    [ADD_DISH_TO_ORDER](state, dish) {
      const { id } = dish
      const { order } = state
      state.order = {
        ...order,
        [id]: {
          ...dish,
          quantity: ((order[id] || dish).quantity || 0) + 1,
          isChecked: true
        }
      }
    },
    [DECREMENT_DISH_QUANTITY_FROM_ORDER](state, id) {
      const { order } = state
      const orderedDish = order[id]
      const quantity = orderedDish.quantity - 1
      if (quantity < 1) {
        Vue.delete(order, id)
        return
      }
      state.order = {
        ...order,
        [id]: {
          ...orderedDish,
          quantity,
          isChecked: true
        }
      }
    },
    [REMOVE_DISH_FROM_ORDER]: (state, id) => Vue.delete(state.order, id)
  },
  actions: {
  }
})