<template>
<div>
    <qrcode-stream @init="onInit" @decode="onDecode"/>
</div>
</template>

<script>
import { QrcodeStream } from 'vue-qrcode-reader'
import { dishesMenuName } from '../views/DishesMenu.vue'

export default {
  components: {
    QrcodeStream
  },

  data: () => ({
    dishesMenuName
  }),

  methods: {
    async onInit(promise) {
      try {
        await promise
      } catch (error) {
        switch (error.name) {
          case error.name === 'NotAllowedError':
            this.error = 'ERROR: you need to grant camera access permisson'
            break
          case error.name === 'NotFoundError':
            this.error = 'ERROR: no camera on this device'
            break
          case error.name === 'NotSupportedError':
            this.error = 'ERROR: secure context required (HTTPS, localhost)'
            break
          case error.name === 'NotReadableError':
            this.error = 'ERROR: is the camera already in use?'
            break
          case error.name === 'OverconstrainedError':
            this.error = 'ERROR: installed cameras are not suitable'
            break
          case error.name === 'StreamApiNotSupportedError':
            this.error = 'ERROR: Stream API is not supported in this browser'
            break
          default:
            this.error = 'UNKNOWN ERROR'
            break
        }
      }
    },

    onDecode() {
      this.$router.push(dishesMenuName)
    }
  }
}
</script>