<template>
  <v-container fluid fill-height style="background: #FFE0B2;">
    <v-row align="center" justify="center">
      <v-col cols="12" sm="10" md="8">

        <v-simple-table fixed-header class="elevation-3"><template v-slot:default>
          <thead><tr><th>Dish name</th><th>Price</th><th>Quantity</th></tr></thead>
          <tbody>
            <tr v-for="dish in dishes" :key="dish.id">
              <td>
                <v-checkbox v-model="dish.isChecked" color="success">
                  <template v-slot:label>
                    <div class="black--text" :class="{ 'unchecked-dish': !dish.isChecked }">
                      {{ dish.name }}
                    </div>
                  </template>
                </v-checkbox>
              </td>
              <td>{{ dish.price * dish.quantity }}</td>
              <td style="min-width: 100px;">
                <v-icon @click="decrementDishCount(dish)">mdi-minus</v-icon>
                {{ dish.quantity }}
                <v-icon @click="incrementDishCount(dish)">mdi-plus</v-icon>
              </td>
            </tr>

            <tr><td colspan="2"/><td>Итого: {{ totalCost }}</td></tr>
          </tbody>
        </template></v-simple-table>

        <div class="text-center pt-2">
          <v-btn color="success" block tile><v-icon left>mdi-check</v-icon>&nbsp;Order</v-btn>
        </div>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { ADD_DISH_TO_ORDER, DECREMENT_DISH_QUANTITY_FROM_ORDER } from '../store'

export default {
  mounted() { this.navigateHomeOnDishesEmpty(this.dishes.length) },
  computed: {
    dishes() { return this.$store.getters.dishes },
    totalCost() {
      return this.dishes.reduce(
        (total, dish) => total + (dish.isChecked ? dish.quantity * dish.price : 0), 0
      )
    }
  },
  watch: {
    dishes(newDishes) { this.navigateHomeOnDishesEmpty(newDishes.length) }
  },
  methods: {
    navigateHomeOnDishesEmpty(dishesCount) { if (dishesCount === 0) this.$router.push('/') },
    incrementDishCount(dish) { this.$store.commit(ADD_DISH_TO_ORDER, dish) },
    decrementDishCount(dish) { this.$store.commit(DECREMENT_DISH_QUANTITY_FROM_ORDER, dish.id) }
  }
}

export const orderPath = '/order'
export const orderName = 'order'
</script>

<style lang="stylus" scoped>
.unchecked-dish
  text-decoration line-through
</style>